package com.example.algorithms;

import java.util.Arrays;
import java.util.Comparator;

public class MergeSort {

    public static <T extends Comparable<T>> void sort(T[] array) {
        if (array == null || array.length <= 1) return;
        @SuppressWarnings("unchecked")
        T[] temp = Arrays.copyOf(array, array.length);
        mergeSort(array, temp, 0, array.length - 1);
    }

    private static <T extends Comparable<T>> void mergeSort(
            T[] array, T[] temp, int left, int right) {
        if (left >= right) return;

        int mid = left + (right - left) / 2;
        mergeSort(array, temp, left, mid);
        mergeSort(array, temp, mid + 1, right);
        merge(array, temp, left, mid, right);
    }

    private static <T extends Comparable<T>> void merge(
            T[] array, T[] temp, int left, int mid, int right) {
        System.arraycopy(array, left, temp, left, right - left + 1);

        int i = left;       // Left subarray index
        int j = mid + 1;    // Right subarray index
        int k = left;       // Merge index

        while (i <= mid && j <= right) {
            if (temp[i].compareTo(temp[j]) <= 0) {
                array[k++] = temp[i++];
            } else {
                array[k++] = temp[j++];
            }
        }

        while (i <= mid) {
            array[k++] = temp[i++];
        }
    }

    public static <T> void sortWithComparator(T[] array, Comparator<T> comparator) {
        if (array == null || array.length <= 1 || comparator == null) return;
        @SuppressWarnings("unchecked")
        T[] temp = Arrays.copyOf(array, array.length);
        mergeSortCmp(array, temp, 0, array.length - 1, comparator);
    }

    private static <T> void mergeSortCmp(
            T[] array, T[] temp, int left, int right, Comparator<T> comparator) {
        if (left >= right) return;

        int mid = left + (right - left) / 2;
        mergeSortCmp(array, temp, left, mid, comparator);
        mergeSortCmp(array, temp, mid + 1, right, comparator);
        mergeCmp(array, temp, left, mid, right, comparator);
    }

    private static <T> void mergeCmp(
            T[] array, T[] temp, int left, int mid, int right, Comparator<T> comparator) {
        System.arraycopy(array, left, temp, left, right - left + 1);

        int i = left;
        int j = mid + 1;
        int k = left;

        while (i <= mid && j <= right) {
            if (comparator.compare(temp[i], temp[j]) <= 0) {
                array[k++] = temp[i++];
            } else {
                array[k++] = temp[j++];
            }
        }

        while (i <= mid) {
            array[k++] = temp[i++];
        }
    }
}

