import java.util.*;

public class Dijkstra {

    public static Map<String, Double> findShortestPaths(
            Map<String, List<Edge>> graph, String start) {
        Map<String, Double> distances = new HashMap<>();
        Map<String, String> predecessors = new HashMap<>();
        Set<String> visited = new HashSet<>();

        PriorityQueue<NodeDistance> pq = new PriorityQueue<>(
            Comparator.comparingDouble(NodeDistance::getDistance)
        );

        for (String node : graph.keySet()) {
            distances.put(node, Double.POSITIVE_INFINITY);
        }
        distances.put(start, 0.0);
        pq.add(new NodeDistance(start, 0.0));

        while (!pq.isEmpty()) {
            NodeDistance current = pq.poll();
            String currentNode = current.getNode();

            if (visited.contains(currentNode)) continue;
            visited.add(currentNode);

            for (Edge edge : graph.getOrDefault(currentNode, Collections.emptyList())) {
                if (visited.contains(edge.getTarget())) continue;

                double newDistance = distances.get(currentNode) + edge.getWeight();
                if (newDistance < distances.getOrDefault(edge.getTarget(), Double.POSITIVE_INFINITY)) {
                    distances.put(edge.getTarget(), newDistance);
                    predecessors.put(edge.getTarget(), currentNode);
                    pq.add(new NodeDistance(edge.getTarget(), newDistance));
                }
            }
        }

        return distances;
    }

    public static List<String> getShortestPath(
            Map<String, List<Edge>> graph, String start, String end) {
        Map<String, Double> distances = findShortestPaths(graph, start);

        if (!distances.containsKey(end) || distances.get(end) == Double.POSITIVE_INFINITY) {
            return Collections.emptyList();
        }

        List<String> path = new ArrayList<>();
        String current = end;
