package com.example.algorithms;

import java.util.ArrayList;
import java.util.List;
import java.util.Stack;

public class BinarySearchTree<T extends Comparable<T>> {

    private TreeNode<T> root;
    private int size;

    public void insert(T value) {
        root = insertRec(root, value);
        size++;
    }

    private TreeNode<T> insertRec(TreeNode<T> node, T value) {
        if (node == null) {
            return new TreeNode<>(value);
        }

        int cmp = value.compareTo(node.value);
        if (cmp < 0) {
            node.left = insertRec(node.left, value);
        } else if (cmp > 0) {
            node.right = insertRec(node.right, value);
        }
        return node;
    }

    public boolean search(T value) {
        return searchRec(root, value);
    }

    private boolean searchRec(TreeNode<T> node, T value) {
        if (node == null) return false;

        int cmp = value.compareTo(node.value);
        if (cmp == 0) return true;
        return cmp < 0 ? searchRec(node.left, value) : searchRec(node.right, value);
    }

    public List<T> inOrderTraversal() {
        List<T> result = new ArrayList<>();
        inOrderRec(root, result);
        return result;
    }

    private void inOrderRec(TreeNode<T> node, List<T> result) {
        if (node != null) {
            inOrderRec(node.left, result);
            result.add(node.value);
            inOrderRec(node.right, result);
        }
    }

    public List<T> iterativeInOrder() {
        List<T> result = new ArrayList<>();
        Stack<TreeNode<T>> stack = new Stack<>();
        TreeNode<T> current = root;

        while (current != null || !stack.isEmpty()) {
            while (current != null) {
                stack.push(current);
                current = current.left;
            }
            current = stack.pop();
            result.add(current.value);
            current = current.right;
        }
        return result;
    }

    public T findMin() {
        if (root == null) throw new NoSuchElementException();
        TreeNode<T> current = root;
        while (current.left != null) {
            current = current.left;
        }
        return current.value;
    }

    public T findMax() {
        if (root == null) throw new NoSuchElementException();
        TreeNode<T> current = root;
        while (current.right != null) {
            current = current.right;
        }
        return current.value;
    }

    public static class TreeNode<T> {
        T value;
        TreeNode<T> left;
        TreeNode<T> right;

        TreeNode(T value) {
            this.value = value;
        }
    }
}

package com.example.algorithms;

import java.util.*;

public class TopologicalSort {

    public static List<String> sort(List<String> vertices, List<Pair<String, String>> edges) {
        Map<String, List<String>> adjList = new HashMap<>();
        Map<String, Integer> inDegree = new HashMap<>();

        for (String v : vertices) {
            adjList.put(v, new ArrayList<>());
            inDegree.put(v, 0);
        }

        for (Pair<String, String> edge : edges) {
            adjList.get(edge.first).add(edge.second);
            inDegree.merge(edge.second, 1, Integer::sum);
        }

        Queue<String> queue = new LinkedList<>();
        for (Map.Entry<String, Integer> entry : inDegree.entrySet()) {
            if (entry.getValue() == 0) {
                queue.offer(entry.getKey());
            }
        }

        List<String> result = new ArrayList<>();
        while (!queue.isEmpty()) {
            String vertex = queue.poll();
            result.add(vertex);

            for (String neighbor : adjList.get(vertex)) {
                int newDegree = inDegree.get(neighbor) - 1;
                inDegree.put(neighbor, newDegree);
                if (newDegree == 0) {
                    queue.offer(neighbor);
                }
            }
        }

        if (result.size() != vertices.size()) {
            throw new IllegalStateException("Graph contains a cycle");
        }

        return result;
    }

    public record Pair<F, S>(F first, S second) {}
}

package com.example.algorithms;

import java.util.LinkedHashMap;
import java.util.Map;

public class LRUCache<K, V> extends LinkedHashMap<K, V> {
    private final int capacity;

    public LRUCache(int capacity) {
        super(capacity, 0.75f, true);
        this.capacity = capacity;
    }

    @Override
    protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {
        return size() > capacity;
    }

    public V getOrCompute(K key, java.util.function.Function<K, V> mappingFunction) {
        V value = get(key);
        if (value == null) {
            value = mappingFunction.apply(key);
            put(key, value);
        }
        return value;
    }

    public void evictAll() {
        clear();
    }

    public int getHitRate(int totalAccesses) {
        return totalAccesses > 0 ? size() * 100 / Math.max(totalAccesses, 1) : 0;
    }
}

