package com.example.algorithms;

import java.util.*;

public class Trie {
    private final TrieNode root = new TrieNode();

    public void insert(String word) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            node.children.putIfAbsent(c, new TrieNode());
            node = node.children.get(c);
        }
        node.isEndOfWord = true;
    }

    public boolean search(String word) {
        return findNode(word) != null && findNode(word).isEndOfWord;
    }

    public boolean startsWith(String prefix) {
        return findNode(prefix) != null;
    }

    public List<String> autocomplete(String prefix, int maxResults) {
        List<String> results = new ArrayList<>();
        TrieNode node = findNode(prefix);
        if (node == null) return results;

        collectWords(node, prefix, results, maxResults);
        return results;
    }

    private TrieNode findNode(String prefix) {
        TrieNode node = root;
        for (char c : prefix.toCharArray()) {
            node = node.children.get(c);
            if (node == null) return null;
        }
        return node;
    }

    private void collectWords(TrieNode node, String prefix,
                              List<String> results, int maxResults) {
        if (results.size() >= maxResults) return;

        if (node.isEndOfWord) {
            results.add(prefix);
        }

        for (Map.Entry<Character, TrieNode> entry : node.children.entrySet()) {
            collectWords(entry.getValue(), prefix + entry.getKey(), results, maxResults);
        }
    }

    public boolean delete(String word) {
        return deleteHelper(root, word, 0);
    }

    private boolean deleteHelper(TrieNode node, String word, int depth) {
        if (depth == word.length()) {
            if (!node.isEndOfWord) return false;
            node.isEndOfWord = false;
            return node.children.isEmpty();
        }

        char c = word.charAt(depth);
        TrieNode child = node.children.get(c);
        if (child == null) return false;

        boolean shouldDeleteChild = deleteHelper(child, word, depth + 1);

        if (shouldDeleteChild) {
            node.children.remove(c);
            return node.children.isEmpty() && !node.isEndOfWord;
        }
        return false;
    }

    private static class TrieNode {
        Map<Character, TrieNode> children = new HashMap<>();
        boolean isEndOfWord = false;
    }
}

package com.example.algorithms;

import java.util.Arrays;

public class Knapsack {

    public static int solve(int capacity, int[] weights, int[] values) {
        int n = weights.length;
        int[][] dp = new int[n + 1][capacity + 1];

        for (int i = 1; i <= n; i++) {
            for (int w = 0; w <= capacity; w++) {
                if (weights[i - 1] <= w) {
                    dp[i][w] = Math.max(
                        dp[i - 1][w],
                        dp[i - 1][w - weights[i - 1]] + values[i - 1]
                    );
                } else {
                    dp[i][w] = dp[i - 1][w];
                }
            }
        }

        return dp[n][capacity];
    }

    public static int solveOptimized(int capacity, int[] weights, int[] values) {
        int n = weights.length;
        int[] dp = new int[capacity + 1];

        for (int i = 0; i < n; i++) {
            for (int w = capacity; w >= weights[i]; w--) {
                dp[w] = Math.max(dp[w], dp[w - weights[i]] + values[i]);
            }
        }

        return dp[capacity];
    }

    public static int[] reconstruct(int capacity, int[] weights, int[] values) {
        int n = weights.length;
        int[][] dp = new int[n + 1][capacity + 1];

        for (int i = 1; i <= n; i++) {
            for (int w = 0; w <= capacity; w++) {
                if (weights[i - 1] <= w) {
                    dp[i][w] = Math.max(
                        dp[i - 1][w],
                        dp[i - 1][w - weights[i - 1]] + values[i - 1]
                    );
                } else {
                    dp[i][w] = dp[i - 1][w];
                }
            }
        }

        int[] selected = new int[n];
        int w = capacity;
        for (int i = n; i > 0 && w > 0; i--) {
            if (dp[i][w] != dp[i - 1][w]) {
                selected[i - 1] = 1;
                w -= weights[i - 1];
            }
        }

        return selected;
    }
}

// Usage:
// int[] weights = {2, 3, 4, 5};
// int[] values = {3, 4, 5, 6};
// int capacity = 5;
// int maxVal = Knapsack.solve(capacity, weights, values); // 7

package com.example.algorithms;

import java.util.*;

public class AStar {

    public record Point(int x, int y) {
        @Override
        public int hashCode() { return Objects.hash(x, y); }
        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (!(o instanceof Point p)) return false;
            return x == p.x && y == p.y;
        }
    }

    public static List<Point> findPath(int[][] grid, Point start, Point goal) {
        PriorityQueue<Node> openSet = new PriorityQueue<>(
            Comparator.comparingLong(n -> n.fScore)
        );
        Map<Point, Node> allNodes = new HashMap<>();

        Node startNode = new Node(start, 0, heuristic(start, goal));
        openSet.add(startNode);
        allNodes.put(start, startNode);

        while (!openSet.isEmpty()) {
            Node current = openSet.poll();

            if (current.point.equals(goal)) {
                return reconstructPath(current);
            }

            for (Point neighbor : getNeighbors(grid, current.point)) {
                Node neighborNode = allNodes.computeIfAbsent(
                    neighbor, p -> new Node(p, 0, 0)
                );

                double tentativeG = current.gScore + distance(current.point, neighbor);
                if (tentativeG < neighborNode.gScore) {
                    neighborNode.parent = current;
                    neighborNode.gScore = tentativeG;
                    neighborNode.hScore = heuristic(neighbor, goal);
                    openSet.remove(neighborNode);
                    openSet.add(neighborNode);
                }
            }
        }

        return Collections.emptyList(); // No path found
    }

    private static List<Point> reconstructPath(Node current) {
        List<Point> path = new ArrayList<>();
        while (current != null) {
            path.add(0, current.point);
            current = current.parent;
        }
        return path;
    }

    private static double heuristic(Point a, Point b) {
        return Math.abs(a.x - b.x) + Math.abs(a.y - b.y); // Manhattan
    }

    private static double distance(Point a, Point b) {
        return Math.sqrt(Math.pow(a.x - b.x, 2) + Math.pow(a.y - b.y, 2));
    }

    private static List<Point> getNeighbors(int[][] grid, Point point) {
        List<Point> neighbors = new ArrayList<>();
        int[][] dirs = {{0,1},{0,-1},{1,0},{-1,0}};
        for (int[] d : dirs) {
            int nx = point.x + d[0];
            int ny = point.y + d[1];
            if (nx >= 0 && ny >= 0 && nx < grid[0].length && ny < grid.length
                && grid[ny][nx] == 0) {
                neighbors.add(new Point(nx, ny));
            }
        }
        return neighbors;
    }

    private static class Node {
        Point point;
        double gScore;
        double hScore;
        Node parent;

        Node(Point point, double g, double h) {
            this.point = point;
            this.gScore = g;
            this.hScore = h;
        }

        long getFScore() { return (long)(gScore + hScore); }
    }
}
